        TbINACBGDiagnosa.setDefaultRenderer(Object.class, new DefaultTableCellRenderer() {

            @Override
            public Component getTableCellRendererComponent(JTable table, Object value,
                    boolean isSelected, boolean hasFocus, int row, int column) {

                // Panggil renderer default dulu
                Component c = super.getTableCellRendererComponent(table, value, isSelected, hasFocus, row, column);

                String codeValue = table.getValueAt(row, 1) != null ? table.getValueAt(row, 1).toString() : "";
                String validcode = table.getValueAt(row, 2) != null ? table.getValueAt(row, 2).toString() : "";

                // Kondisi: jika code == "400" → baris merah atau validcode == 0
                if (codeValue.contains("(IM tidak berlaku)") || validcode.equals("0")) {
                    c.setBackground(Color.RED);
                    c.setForeground(Color.BLACK);
                } else {
                    // reset ke warna default saat tidak dipilih
                    if (isSelected) {
                        c.setBackground(table.getSelectionBackground());
                        c.setForeground(table.getSelectionForeground());
                    } else {
                        c.setBackground(Color.WHITE);
                        c.setForeground(Color.BLACK);
                    }
                }

                return c;
            }
        });

