        cmb_description_topup.addActionListener(new java.awt.event.ActionListener() {
            public void actionPerformed(java.awt.event.ActionEvent evt) {
                if (cmb_description_topup.getSelectedItem() != null) {
                    String selectedItem = cmb_description_topup.getSelectedItem().toString();
                    try {
                        double nbrVal = Double.parseDouble(txt_nbr.getText().replaceAll(",", "").replaceAll(" ", "").trim().isEmpty() ? "0" : txt_nbr.getText().replaceAll(",", "").replaceAll(" ", "").trim());
                        double drgWeight = Double.parseDouble(drg_cost_weight.getText().trim().isEmpty() ? "0" : drg_cost_weight.getText().trim());
                        double topupWeight = 0;
                        
                        if (selectedItem.equals("None")) {
                            code_topup.setText("");
                            cost_weight_topup.setText("0.00");
                            txt_type_topup.setText("None");
                        } else {
                            String codeVal = codetopupIDRGMap.get(selectedItem);
                            String weightVal = weighttopupIDRGMap.get(selectedItem);
                            String typeVal = typetopupIDRGMap.get(selectedItem);
                            code_topup.setText(codeVal != null ? codeVal : "");
                            cost_weight_topup.setText(weightVal != null ? weightVal : "0.00");
                            txt_type_topup.setText(typeVal != null ? typeVal : "None");
                            topupWeight = Double.parseDouble(cost_weight_topup.getText().trim().isEmpty() ? "0" : cost_weight_topup.getText().trim());
                        }
                        
                        double totalCostWeight = drgWeight + topupWeight;
                        txt_total_cost_weight.setText(String.format(Locale.US, "%.4f", totalCostWeight));
                        
                        double totalKlaim = nbrVal * totalCostWeight;
                        long totalKlaimLong = Math.round(totalKlaim);
                        txt_total_klaim.setText(String.valueOf(totalKlaimLong));
                        
                        // Update to database
                        if (!isLoadingTopup && !id_resume_idrg.getText().equals("")) {
                            try {
                                String query = "UPDATE resume_idrg SET total_cost_weight = ?, total_tarif_idrg = ?, nbr = ? WHERE id_resume_idrg = ?";
                                ps = koneksi.prepareStatement(query);
                                ps.setDouble(1, totalCostWeight);
                                ps.setDouble(2, totalKlaimLong);
                                ps.setDouble(3, nbrVal);
                                ps.setString(4, id_resume_idrg.getText());
                                int rows = ps.executeUpdate();
                                if (rows > 0) {
                                    Sequel.Commit();
                                }
                            } catch (SQLException ex) {
                                System.err.println("Error updating topup price: " + ex.getMessage());
                            } finally {
                                if (ps != null) {
                                    ps.close();
                                }
                            }
                        }
                    } catch (Exception e) {
                        System.err.println("Error adjusting topup price: " + e.getMessage());
                    }
                }
            }
        });
        
