            CmbJam1.setEnabled(false);
            CmbMenit1.setEnabled(false);
            CmbDetik1.setEnabled(false);
            timestamp_intubasi_2.setEnabled(false);
            CmbJam2.setEnabled(false);
            CmbMenit2.setEnabled(false);
            CmbDetik2.setEnabled(false);
