    private boolean diagnosa_set() {
        boolean success = false;
        String json_set_diagnosa = "";
        String data_diagnosa_set = "";
        int column_kode_icdx = 0;
        int column_nama_icdx = 1;
        for (int row = 0; row < diagnosa_model.getRowCount(); row++) {
            Object value_code_icdx = diagnosa_model.getValueAt(row, column_kode_icdx);
            Object value_nama_icdx = diagnosa_model.getValueAt(row, column_nama_icdx);
            data_diagnosa_set = data_diagnosa_set + value_code_icdx;
            if (row == (diagnosa_model.getRowCount() - 1)) {
                System.out.println("Data diaganosa set: " + data_diagnosa_set);
            } else {
                data_diagnosa_set = data_diagnosa_set + "#";
            }
        }

        if (!txtSep.getText().equals("")) {
            try {
                OkHttpClient client = new OkHttpClient().newBuilder().build();
                MediaType mediaType = MediaType.parse("application/json");
                json_set_diagnosa = "{\n" +
                        "    \"metadata\": {\n" +
                        "        \"method\": \"idrg_diagnosa_set\",\n" +
                        "        \"nomor_sep\": \"" + txtSep.getText() + "\"\n" +
                        "    },\n" +
                        "    \"data\": {\n" +
                        "        \"diagnosa\": \"" + data_diagnosa_set + "\"\n" +
                        "    }\n" +
                        "}";
                RequestBody body = RequestBody.create(mediaType, json_set_diagnosa);
                System.out.println("JSON New Claim: " + json_set_diagnosa);
                Request request = new Request.Builder()
                        .url(url_eklaim)
                        .method("POST", body)
                        .addHeader("Content-Type", "application/json")
                        // .addHeader("Authorization", "Bearer "+api.TokenSatuSehat()+"")
                        .build();
                Response response = client.newCall(request).execute();
                if (response.isSuccessful()) {
                    String responseBody = response.body().string(); // dari OkHttp
                    System.out.println("Response: " + responseBody);
                    JsonObject root = JsonParser.parseString(responseBody).getAsJsonObject();
                    // meta
                    JsonObject response_eklaim = root.getAsJsonObject("metadata");
                    String message = response_eklaim.get("message").getAsString();

                    if (message.equals("Ok")) {
                        notif_auto_close("Send Data Diagnosa Set Berhasil: " + message);
                        success = true;
                    } else {
                        notif_auto_close("Send Data Diagnosa Set Gagal: " + message);
                    }
                } else {
                    System.out.println("Ada error");
                    System.out.println("Error: " + response.body().string());
                    status_kirim_new_claim = "Tidak berhasil";
                    notif_auto_close("Send Data Diagnosa Set Gagal.");
                }
            } catch (IOException ex) {
                Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
            }
        }
        return success;
    }

    private boolean procedure_set() {
        boolean success = false;
        String json_set_procedure = "";
        String data_procedure_set = "";

        if (!txtSep.getText().equals("")) {
            try {
                OkHttpClient client = new OkHttpClient().newBuilder().build();
                MediaType mediaType = MediaType.parse("application/json");
                if (prosedur_model.getRowCount() > 0) {
                    int column_kode_icdix = 0;
                    int column_nama_icdix = 1;
                    int column_multiplicity_icdix = 4;
                    for (int row = 0; row < prosedur_model.getRowCount(); row++) {
                        Object value_code_icdix = prosedur_model.getValueAt(row, column_kode_icdix);
                        Object value_nama_icdix = prosedur_model.getValueAt(row, column_nama_icdix);
                        Object value_multiplicity_icdix = prosedur_model.getValueAt(row, column_multiplicity_icdix);
                        // tambah multiplicity
                        if (value_multiplicity_icdix.equals("")) {
                            data_procedure_set = data_procedure_set + value_code_icdix;
                        } else {
                            data_procedure_set = data_procedure_set + value_code_icdix + "+" + value_multiplicity_icdix;
                        }

                        if (row == (prosedur_model.getRowCount() - 1)) {
                            System.out.println("Data procedure set: " + data_procedure_set);
                        } else {
                            data_procedure_set = data_procedure_set + "#";
                        }
                    }
                    json_set_procedure = "{\n" +
                            "    \"metadata\": {\n" +
                            "        \"method\": \"idrg_procedure_set\",\n" +
                            "        \"nomor_sep\": \"" + txtSep.getText() + "\"\n" +
                            "    },\n" +
                            "    \"data\": {\n" +
                            "        \"procedure\": \"" + data_procedure_set + "\"\n" +
                            "    }\n" +
                            "}";
                } else {
                    prosedur_model.setRowCount(0);
                    json_set_procedure = "{\n" +
                            "    \"metadata\": {\n" +
                            "        \"method\": \"idrg_procedure_set\",\n" +
                            "        \"nomor_sep\": \"" + txtSep.getText() + "\"\n" +
                            "    },\n" +
                            "    \"data\": {\n" +
                            "        \"procedure\": \"#\"\n" +
                            "    }\n" +
                            "}";
                }
                RequestBody body = RequestBody.create(mediaType, json_set_procedure);
                System.out.println("JSON New Claim: " + json_set_procedure);
                Request request = new Request.Builder()
                        .url(url_eklaim)
                        .method("POST", body)
                        .addHeader("Content-Type", "application/json")
                        // .addHeader("Authorization", "Bearer "+api.TokenSatuSehat()+"")
                        .build();
                Response response = client.newCall(request).execute();
                if (response.isSuccessful()) {
                    String responseBody = response.body().string(); // dari OkHttp
                    System.out.println("Response: " + responseBody);
                    JsonObject root = JsonParser.parseString(responseBody).getAsJsonObject();
                    // meta
                    JsonObject response_eklaim = root.getAsJsonObject("metadata");
                    String message = response_eklaim.get("message").getAsString();

                    if (message.equals("Ok")) {
                        notif_auto_close("Send Data Prosedur Set Berhasil: " + message);
                        success = true;
                    } else {
                        notif_auto_close("Send Data Prosedur Set Gagal: " + message);
                    }
                } else {
                    System.out.println("Ada error");
                    System.out.println("Error: " + response.body().string());
                    status_kirim_new_claim = "Tidak berhasil";
                    notif_auto_close("Send Data Prosedur Set Gagal.");
                }
            } catch (IOException ex) {
                Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
            }
        }
        return success;
    }

    private void grouping_idrg_stage_1() {
        String json_grouping_idrg = "";

        if (!txtSep.getText().equals("")) {
            try {
                OkHttpClient client = new OkHttpClient().newBuilder().build();
                MediaType mediaType = MediaType.parse("application/json");
                json_grouping_idrg = "{\n" +
                        "    \"metadata\": {\n" +
                        "        \"method\": \"grouper\",\n" +
                        "        \"stage\": \"1\",\n" +
                        "        \"grouper\": \"idrg\"\n" +
                        "    },\n" +
                        "    \"data\": {\n" +
                        "        \"nomor_sep\": \"" + txtSep.getText() + "\"\n" +
                        "    }\n" +
                        "}";
                RequestBody body = RequestBody.create(mediaType, json_grouping_idrg);
                System.out.println("JSON Grouping Stage 1: " + json_grouping_idrg);
                Request request = new Request.Builder()
                        .url(url_eklaim)
                        .method("POST", body)
                        .addHeader("Content-Type", "application/json")
                        // .addHeader("Authorization", "Bearer "+api.TokenSatuSehat()+"")
                        .build();
                Response response = client.newCall(request).execute();
                if (response.isSuccessful()) {
                    String responseBody = response.body().string(); // dari OkHttp
                    System.out.println("Response: " + responseBody);
                    JsonObject root = JsonParser.parseString(responseBody).getAsJsonObject();
                    // meta
                    JsonObject response_eklaim = root.getAsJsonObject("metadata");
                    String message = response_eklaim.get("message").getAsString();

                    // response_idrg
                    JsonObject response_grouper = root.getAsJsonObject("response_idrg");
                    String mdc_number = getJsonString(response_grouper, "mdc_number");
                    String mdc_description = getJsonString(response_grouper, "mdc_description");
                    String drg_code = getJsonString(response_grouper, "drg_code");
                    String drg_description = getJsonString(response_grouper, "drg_description");
                    
                    // tambahan baru update idrg
                    String script_version = getJsonString(response_grouper, "script_version");
                    txt_script_version.setText(script_version);
                    String logic_version = getJsonString(response_grouper, "logic_version");
                    txt_logic_version.setText(logic_version);
                    String cost_weight = getJsonString(response_grouper, "cost_weight");
                    drg_cost_weight.setText(cost_weight);
                    String sub_acute_weight = getJsonString(response_grouper, "sub_acute_weight");
                    txt_sub_acute_weight.setText(sub_acute_weight);
                    String chronic_weight = getJsonString(response_grouper, "chronic_weight");
                    txt_chronic_weight.setText(chronic_weight);
                    String nbr = getJsonString(response_grouper, "nbr");
                    txt_nbr.setText(nbr);
                    String total_cost_weight = getJsonString(response_grouper, "total_cost_weight");
                    txt_total_cost_weight.setText(total_cost_weight);
                    
                    String total_tarif = getJsonString(response_grouper, "total_tarif");
                    if (total_tarif.isEmpty() || total_tarif.equals("0")) {
                        try {
                            double nbrVal = Double.parseDouble(nbr.replaceAll(",", "").replaceAll(" ", "").trim().isEmpty() ? "0" : nbr.replaceAll(",", "").replaceAll(" ", "").trim());
                            double cwVal = Double.parseDouble(total_cost_weight.trim().isEmpty() ? "0" : total_cost_weight.trim());
                            total_tarif = String.valueOf(Math.round(nbrVal * cwVal));
                        } catch (Exception e) {
                            total_tarif = "0";
                        }
                    }
                    txt_total_klaim.setText(total_tarif);
                    String status_cd = getJsonString(response_grouper, "status_cd");
                    txtStatusIDRG.setText(status_cd);
                    JsonObject topup_options = null;

                    if (message.equals("Ok")) {
                        String clean_total_tarif = total_tarif.replaceAll(",", "").replaceAll(" ", "").trim();
                        if (clean_total_tarif.isEmpty()) {
                            clean_total_tarif = "0";
                        }
                        String clean_nbr = nbr.replaceAll(",", "").replaceAll(" ", "").trim();
                        if (clean_nbr.isEmpty()) {
                            clean_nbr = "0";
                        }
                        
                        String query_update = "UPDATE resume_idrg SET  \n"
                                + "mdc_code = '" + mdc_number + "', \n"
                                + "mdc = '" + mdc_description + "', \n"
                                + "drg_code = '" + drg_code + "', \n"
                                + "drg = '" + drg_description + "', \n"
                                + "script_version = '" + script_version + "', \n"
                                + "logic_version = '" + logic_version + "', \n"
                                + "cost_weight = '" + cost_weight + "', \n"
                                + "sub_acute_weight = '" + sub_acute_weight + "',  \n"
                                + "chronic_weight = '" + chronic_weight + "', \n"
                                + "nbr = '" + clean_nbr + "', \n"
                                + "total_cost_weight = '" + total_cost_weight + "', \n"
                                + "total_tarif_idrg = '" + clean_total_tarif + "' \n"
                                // total rs belum
                                + "WHERE id_resume_idrg = '" + id_resume_idrg.getText() + "';";

                        System.out.println("Query Update Resume IDRG: \n" + query_update);
                        ps = koneksi.prepareStatement(query_update);
                        int affected_row = ps.executeUpdate();
                        System.out.println("Affected rows (Resume IDRG): " + affected_row);
                        if (affected_row > 0) {
                            // update status idrg grouper
                            try {
                                String query_update_idrg_grouper = "UPDATE resume_idrg SET  \n"
                                        + "status_grouper_idrg = 'Y', \n"
                                        + "status_idrg = 'normal', \n"
                                        + "info_idrg = CURRENT_TIMESTAMP() \n"
                                        + "WHERE id_resume_idrg = '" + id_resume_idrg.getText() + "';";
                                System.out.println("Query Update Status Grouper: \n" + query_update_idrg_grouper);
                                ps_grouper = koneksi.prepareStatement(query_update_idrg_grouper);
                                int affected_row_grouper = ps_grouper.executeUpdate();
                                System.out.println("Affected rows (Status Grouper): " + affected_row_grouper);
                                if (affected_row_grouper > 0) {
                                    Sequel.Commit();
                                    cek_grouper_idrg();
                                    // notif_auto_close("Send Data IDRG Berhasil: "+message);
                                    notif_auto_close("Grouping Stage 1 Berhasil: " + message);
                                    refresh_all_page();
                                } else {
                                    notif_auto_close("Update data resume gagal. Silahkan hubungi IT.");
                                }
                            } catch (SQLException ex) {
                                System.err.println("SQLException in grouping_idrg_stage_1 inner: " + ex.getMessage());
                                ex.printStackTrace();
                                Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
                            } finally {
                                if (ps_grouper != null) {
                                    try {
                                        ps_grouper.close();
                                    } catch (SQLException ex) {
                                        Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
                                    }
                                }
                            }
                        } else {
                            notif_auto_close("Update data resume gagal. Silahkan hubungi IT.");
                        }
                        
                        // simpan top up
                        try {
                            isLoadingTopup = true;
                            jumlah_array_special_cmg = 0;
                            cmb_description_topup.removeAllItems();
                            cmb_description_topup.addItem("None");
                            codetopupIDRGMap.clear();
                            weighttopupIDRGMap.clear();
                            typetopupIDRGMap.clear();

                            if (response_grouper != null &&
                                response_grouper.has("topup_options") &&
                                response_grouper.get("topup_options").isJsonArray()) {

                                JsonArray array_special_cmg = response_grouper.get("topup_options").getAsJsonArray();
                                // ambil jumlah array_special_cmg
                                jumlah_array_special_cmg = array_special_cmg.size();

                                // Hapus data topup lama dari database
                                try {
                                    ps = koneksi.prepareStatement("DELETE FROM topup_idrg WHERE id_resume_idrg = '" + id_resume_idrg.getText() + "'");
                                    ps.executeUpdate();
                                } catch (Exception e) {
                                    System.err.println("Error deleting old topup options: " + e);
                                } finally {
                                    if (ps != null) {
                                        ps.close();
                                    }
                                }

                                String local_code_topup = "", local_description_topup = "", local_type_topup = "", local_cost_weight_topup = "";
                                if (jumlah_array_special_cmg > 0) {
                                    for (int j = 0; j < jumlah_array_special_cmg; j++) {
                                        local_type_topup = array_special_cmg.get(j).getAsJsonObject().get("type").getAsString();
                                        local_code_topup = array_special_cmg.get(j).getAsJsonObject().get("code").getAsString();
                                        local_description_topup = array_special_cmg.get(j).getAsJsonObject().get("description").getAsString();
                                        local_cost_weight_topup = array_special_cmg.get(j).getAsJsonObject().get("cost_weight").getAsString();

                                        cmb_description_topup.addItem(local_description_topup);
                                        codetopupIDRGMap.put(local_description_topup, local_code_topup);
                                        weighttopupIDRGMap.put(local_description_topup, local_cost_weight_topup);
                                        typetopupIDRGMap.put(local_description_topup, local_type_topup);
                                        try {
                                            ps = koneksi.prepareStatement(
                                                "INSERT INTO topup_idrg (id_resume_idrg, type_topup, code_topup, description_topup, cost_weight_topup) VALUES("
                                                        + "'" + id_resume_idrg.getText() + "',"
                                                        + "'" + local_type_topup + "',"
                                                        + "'" + local_code_topup + "',"
                                                        + "'" + local_description_topup + "',"
                                                        + "'" + local_cost_weight_topup + "'"
                                                        + ")");
                                            affected_row = ps.executeUpdate();
                                            if (affected_row > 0) {
                                                System.out.println("simpan top up idrg option berhasil: " + local_type_topup + " " + local_code_topup
                                                        + " " + local_description_topup);
                                            } else {
                                                System.out.println("simpan top up idrg option gagal.");
                                            }
                                        } catch (Exception e) {
                                            System.err.println("Error line 10032: "+e);
                                        } finally {
                                            ps.close();
                                        }
                                        
                                    }
                                }
                            }
                            BtnGrouperIDRG2.setEnabled(jumlah_array_special_cmg > 0);
                        } finally {
                            isLoadingTopup = false;
                        }

                        // Set the selected index AFTER isLoadingTopup is set to false.
                        // This triggers the JComboBox Action Listener, updating the top-up details 
                        // and persisting the selected top-up's weight and price in the database.
                        if (jumlah_array_special_cmg > 0) {
                            cmb_description_topup.setSelectedIndex(jumlah_array_special_cmg);
                        } else {
                            cmb_description_topup.setSelectedIndex(0);
                        }
                    } else {
                        notif_auto_close(message);
                    }
                } else {
                    System.out.println("Ada error");
                    System.out.println("Error: " + response.body().string());
                    status_kirim_new_claim = "Tidak berhasil";
                    notif_auto_close("Grouping Stage 1 Gagal.");
                }
            } catch (IOException ex) {
                Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
            } catch (SQLException ex) {
                System.err.println("SQLException in grouping_idrg_stage_1 outer: " + ex.getMessage());
                ex.printStackTrace();
                Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
            } finally {
                if (ps != null) {
                    try {
                        ps.close();
                    } catch (SQLException ex) {
                        Logger.getLogger(DlgIDRGProses.class.getName()).log(Level.SEVERE, null, ex);
                    }
                }
            }
        }
    }

