    private OkHttpClient getUnsafeOkHttpClient() {
        try {
            TrustManager[] trustAllCerts = new TrustManager[]{
                new X509TrustManager() {
                    public void checkClientTrusted(X509Certificate[] chain, String authType) {}
                    public void checkServerTrusted(X509Certificate[] chain, String authType) {}
                    public X509Certificate[] getAcceptedIssuers() {
                        return new X509Certificate[]{};
                    }
                }
            };

            SSLContext sslContext = SSLContext.getInstance("SSL");
            sslContext.init(null, trustAllCerts, new SecureRandom());

            javax.net.ssl.SSLSocketFactory sslSocketFactory = sslContext.getSocketFactory();

            OkHttpClient.Builder builder = new OkHttpClient.Builder();
            builder.sslSocketFactory(sslSocketFactory, (X509TrustManager) trustAllCerts[0]);
            builder.hostnameVerifier((hostname, session) -> true);

            return builder.build();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
    
    private static void trustAllSSL() throws Exception {
        TrustManager[] trustAllCerts = new TrustManager[]{
            new X509TrustManager() {
                public void checkClientTrusted(
                        java.security.cert.X509Certificate[] chain, String authType) {}
                public void checkServerTrusted(
                        java.security.cert.X509Certificate[] chain, String authType) {}
                public java.security.cert.X509Certificate[] getAcceptedIssuers() {
                    return new java.security.cert.X509Certificate[]{};
                }
            }
        };

        SSLContext sc = SSLContext.getInstance("TLS");
        sc.init(null, trustAllCerts, new java.security.SecureRandom());
        HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory());
        HttpsURLConnection.setDefaultHostnameVerifier((h, s) -> true);
    }
    
    private void tampilHasilLab() {
        try {
            Valid.tabelKosong(TabModeHasilLab);
            ps_hasil_lab = koneksi.prepareStatement(
                    "SELECT \n" +
                            "	periksa_lab.kd_jenis_prw, \n" +
                            "	periksa_lab.no_rawat, \n" +
                            "   periksa_lab.kd_jenis_prw, \n" +
                            "   periksa_lab.kategori, \n" +
                            "   periksa_lab.jam, \n" +
                            "   jns_perawatan_lab.nm_perawatan \n" +
                            // " GROUP_CONCAT(jns_perawatan_lab.nm_perawatan) AS nm_perawatan\n" +
                            "FROM `periksa_lab`\n" +
                            "LEFT JOIN reg_periksa ON periksa_lab.no_rawat = reg_periksa.no_rawat\n" +
                            "LEFT JOIN jns_perawatan_lab ON periksa_lab.kd_jenis_prw = jns_perawatan_lab.kd_jenis_prw\n"
                            +
                            "WHERE reg_periksa.no_rkm_medis = ? \n" +
                            // "GROUP BY periksa_lab.no_rawat \n" +
                            "ORDER BY periksa_lab.no_rawat DESC;");
            try {
                ps_hasil_lab.setString(1, txtNoRm.getText());
                rs_hasil_lab = ps_hasil_lab.executeQuery();
                /// System.out.println("rs_hasil_lab: "+ps_hasil_lab.toString());

                while (rs_hasil_lab.next()) {

                    if (rs_hasil_lab.getString("kategori") != null) {
                        switch (rs_hasil_lab.getString("kategori")) {
                            case "PK":
                                noorder = Sequel.cariIsi("SELECT noorder FROM `permintaan_lab` WHERE no_rawat = '"
                                        + rs_hasil_lab.getString("no_rawat") + "' AND jam_hasil = '"
                                        + rs_hasil_lab.getString("jam") + "'");
                                break;
                            case "PA":
                                noorder = Sequel.cariIsi("SELECT noorder FROM `permintaan_labpa` WHERE no_rawat = '"
                                        + rs_hasil_lab.getString("no_rawat") + "' AND jam_hasil = '"
                                        + rs_hasil_lab.getString("jam") + "'");
                                break;
                            case "MB":
                                noorder = Sequel.cariIsi("SELECT noorder FROM `permintaan_labmb` WHERE no_rawat = '"
                                        + rs_hasil_lab.getString("no_rawat") + "' AND jam_hasil = '"
                                        + rs_hasil_lab.getString("jam") + "'");
                                break;
                            default:
                                noorder = "-";
                        }
                    } else {
                        noorder = "-";
                    }

                    TabModeHasilLab.addRow(new Object[] {
                            rs_hasil_lab.getString("no_rawat"),
                            rs_hasil_lab.getString("kategori"),
                            noorder,
                            rs_hasil_lab.getString("nm_perawatan")
                    });
                }
            } catch (Exception e) {
                System.out.println("Notifikasi : " + e);
            } finally {
                if (rs_hasil_radiologi != null) {
                    rs_hasil_radiologi.close();
                }
                if (ps_hasil_radiologi != null) {
                    ps_hasil_radiologi.close();
                }
            }
        } catch (Exception e) {
            System.out.println("Notifikasi : " + e);
        }
    }

    private void tampilHasilRadiologi() {
        try {
            Valid.tabelKosong(TabModeHasilRadiologi);
            ps_hasil_radiologi = koneksi.prepareStatement(
                    "SELECT  "
                            + "hasil_pacs_radiologi.no_order as noorder, " // "No Order",
                            + "hasil_pacs_radiologi.tanggal_order, " // "No Rawat",
                            + "hasil_pacs_radiologi.kd_jenis_prw, " // "Kode Tindakan",
                            + "hasil_pacs_radiologi.tindakan_radiologi, " // "Tindakan",
                            + "hasil_pacs_radiologi.dokter_radiolog, " // "Dokter/Paramedis",
                            + "hasil_pacs_radiologi.link_ris " // "View Hasil"
                            + "FROM `hasil_pacs_radiologi` "
                            + "WHERE hasil_pacs_radiologi.no_rm = ? "
                            + "ORDER BY hasil_pacs_radiologi.tanggal_order DESC");

            try {
                ps_hasil_radiologi.setString(1, txtNoRm.getText());
                rs_hasil_radiologi = ps_hasil_radiologi.executeQuery();
                // System.out.println("rs_hasil_radiologi: "+ps_hasil_radiologi.toString());

                // System.out.println("noRM : "+TNoRM.getText());
                while (rs_hasil_radiologi.next()) {
                    TabModeHasilRadiologi.addRow(new Object[] {
                            rs_hasil_radiologi.getString("noorder"), // No Rontgen
                            rs_hasil_radiologi.getString("tanggal_order"), // No Rontgen -> ganti tanggal order
                            rs_hasil_radiologi.getString("kd_jenis_prw"), // Nama Tindakan
                            rs_hasil_radiologi.getString("tindakan_radiologi"), // Nama Tindakan
                            rs_hasil_radiologi.getString("dokter_radiolog"), // Dokter/Paramedis
                            rs_hasil_radiologi.getString("link_ris") // link view pacs
                    });
                }
            } catch (Exception e) {
                System.out.println("Notifikasi : " + e);
            } finally {
                if (rs_hasil_radiologi != null) {
                    rs_hasil_radiologi.close();
                }
                if (ps_hasil_radiologi != null) {
                    ps_hasil_radiologi.close();
                }
            }
        } catch (Exception e) {
            System.out.println("Notifikasi : " + e);
        }
    }
    
    private String getJsonString(JsonObject obj, String key) {
        if (obj == null || !obj.has(key) || obj.get(key).isJsonNull()) {
            return "";
        }
        return obj.get(key).getAsString();
    }

    private void selectComboBoxItem(javax.swing.JComboBox<String> comboBox, String dbDesc, String dbCode, String dbTariff, 
                                    java.util.Map<String, String> codeMap, java.util.Map<String, String> tariffMap) {
        if (dbDesc == null || dbDesc.trim().isEmpty() || dbDesc.equalsIgnoreCase("None")) {
            comboBox.setSelectedItem("None");
            return;
        }
        
        String matchedItem = null;
        
        // Try exact match first
        for (int i = 0; i < comboBox.getItemCount(); i++) {
            String item = comboBox.getItemAt(i);
            if (item != null && item.equals(dbDesc)) {
                matchedItem = item;
                break;
            }
        }
        
        // Try case-insensitive match next
        if (matchedItem == null) {
            for (int i = 0; i < comboBox.getItemCount(); i++) {
                String item = comboBox.getItemAt(i);
                if (item != null && item.equalsIgnoreCase(dbDesc)) {
                    matchedItem = item;
                    break;
                }
            }
        }
        
        // Try code-based match next
        if (matchedItem == null && dbCode != null && !dbCode.trim().isEmpty() && codeMap != null) {
            String cleanDbCode = dbCode.replace("-", "").trim();
            for (int i = 0; i < comboBox.getItemCount(); i++) {
                String item = comboBox.getItemAt(i);
                String code = codeMap.get(item);
                if (code != null && !code.trim().isEmpty()) {
                    String cleanCode = code.replace("-", "").trim();
                    if (cleanDbCode.equalsIgnoreCase(cleanCode) || 
                        cleanDbCode.startsWith(cleanCode) || 
                        cleanCode.startsWith(cleanDbCode)) {
                        matchedItem = item;
                        break;
                    }
                }
            }
        }
        
        if (matchedItem != null) {
            if (codeMap != null) {
                codeMap.put(matchedItem, dbCode != null ? dbCode : "");
            }
            if (tariffMap != null) {
                tariffMap.put(matchedItem, dbTariff != null ? dbTariff : "0");
            }
            comboBox.setSelectedItem(matchedItem);
        } else {
            // Fallback: put in maps and select directly
            if (codeMap != null) {
                codeMap.put(dbDesc, dbCode != null ? dbCode : "");
            }
            if (tariffMap != null) {
                tariffMap.put(dbDesc, dbTariff != null ? dbTariff : "0");
            }
            comboBox.setSelectedItem(dbDesc);
        }
    }

